/**
 * @summary Get the public digital menu for a QR code slug
 */
export const getGetPublicMenuUrl = (
  slug: string,
  params?: GetPublicMenuParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/public/menu/${slug}?${stringifiedParams}`
    : `/api/public/menu/${slug}`;
};

export const getPublicMenu = async (
  slug: string,
  params?: GetPublicMenuParams,
  options?: RequestInit,
): Promise<PublicMenu> => {
  return customFetch<PublicMenu>(getGetPublicMenuUrl(slug, params), {
    ...options,
    method: "GET",
  });
};

export const getGetPublicMenuQueryKey = (
  slug: string,
  params?: GetPublicMenuParams,
) => {
  return [`/api/public/menu/${slug}`, ...(params ? [params] : [])] as const;
};

export const getGetPublicMenuQueryOptions = <
  TData = Awaited<ReturnType<typeof getPublicMenu>>,
  TError = ErrorType<void>,
>(
  slug: string,
  params?: GetPublicMenuParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getPublicMenu>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetPublicMenuQueryKey(slug, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getPublicMenu>>> = ({
    signal,
  }) => getPublicMenu(slug, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!slug,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getPublicMenu>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

